  func addStrokeAnimations(for stroke: StrokeShapeItem, context: LayerAnimationContext) throws {
    lineJoin = stroke.lineJoin.caLineJoin
    lineCap = stroke.lineCap.caLineCap
    miterLimit = CGFloat(stroke.miterLimit)

    if let strokeColor = stroke.strokeColor {
      try addAnimation(
        for: .strokeColor,
        keyframes: strokeColor,
        value: \.cgColorValue,
        context: context
      )
    }

    try addAnimation(
      for: .lineWidth,
      keyframes: stroke.width,
      value: \.cgFloatValue,
      context: context
    )

    try addOpacityAnimation(for: stroke, context: context)

    if let (dashPattern, dashPhase) = stroke.dashPattern?.shapeLayerConfiguration {
      let lineDashPattern = try dashPattern.map {
        try KeyframeGroup(keyframes: $0)
          .exactlyOneKeyframe(context: context, description: "stroke dashPattern").cgFloatValue
      }

      if lineDashPattern.isSupportedLayerDashPattern {
        self.lineDashPattern = lineDashPattern as [NSNumber]
      }

      try addAnimation(
        for: .lineDashPhase,
        keyframes: KeyframeGroup(keyframes: dashPhase),
        value: \.cgFloatValue,
        context: context
      )
    }
  }

fileprivate func makeAutomaticEngineLayer(for animation: LottieAnimation) -> CoreAnimationLayer? {
  do {
    // Attempt to set up the Core Animation layer. This can either throw immediately in `init`,
    // or throw an error later in `CALayer.display()` that will be reported in `didSetUpAnimation`.
    let coreAnimationLayer = try CoreAnimationLayer(
      animation: animation,
      imageProvider: imageProvider.cachedImageProvider,
      textProvider: textProvider,
      fontProvider: fontProvider,
      maskAnimationToBounds: maskAnimationToBounds,
      compatibilityTrackerMode: .abort,
      logger: logger
    )

    coreAnimationLayer.didSetUpAnimation = { [weak self] issues in
      self?.automaticEngineLayerDidSetUpAnimation(issues)
    }

    return coreAnimationLayer
  } catch {
    if case CompatibilityTracker.Error.encounteredCompatibilityIssue(let compatibilityIssue) = error {
      automaticEngineLayerDidSetUpAnimation([compatibilityIssue])
    } else {
      // This should never happen, because we expect `CoreAnimationLayer` to only throw
      // `CompatibilityTracker.Error.encounteredCompatibilityIssue` errors.
      logger.assertionFailure("Encountered unexpected error \(error)")
      automaticEngineLayerDidSetUpAnimation([])
    }

    return nil
  }
}

func encode(to encoder: Encoder) throws {
    var container = encoder.container(keyedBy: CodingKeys.self)
    guard let type = EntityAddToActionType(rawValue: action.actionType) else {
        throw EntityAddToError.encodingFailed
    }
    try container.encode(type, forKey: .type)

    switch type {
    case .carPlayQuickAccess:
        if let typed = action as? CarPlayQuickAccessAction {
            try container.encode(typed, forKey: .data)
        } else {
            throw EntityAddToError.encodingFailed
        }
    case .watchItem:
        if let typed = action as? WatchItemAction {
            try container.encode(typed, forKey: .data)
        } else {
            throw EntityAddToError.encodingFailed
        }
    case .customWidget:
        if let typed = action as? CustomWidgetAction {
            try container.encode(typed, forKey: .data)
        } else {
            throw EntityAddToError.encodingFailed
        }
    }
}

private func addEntityToWidget(
    widget: CustomWidget,
    entityId: String,
    serverId: String,
    webViewController: WebViewControllerProtocol
) {
    Current.Log.info("Adding entity \(entityId) to widget '\(widget.name)'")

    // Create a new MagicItem for the entity
    let newItem = MagicItem(
        id: entityId,
        serverId: serverId,
        type: .entity
    )

    // Create updated widget with the new item
    var updatedWidget = widget
    updatedWidget.items.append(newItem)

    // Save to database
    do {
        try Current.database().write { db in
            try updatedWidget.update(db)
        }

        // Open the widget creation view to let user see and further customize
        let widgetCreationView = WidgetCreationView(widget: updatedWidget) {
            // Reload widgets after changes
        }
        let hostingController = widgetCreationView
            .embeddedInHostingController()

        webViewController.presentOverlayController(controller: hostingController, animated: true)
    } catch {
        Current.Log.error("Failed to add entity to widget: \(error.localizedDescription)")
    }
}

func showAssist(server: Server, pipeline: String = "", autoStartRecording: Bool = false) {
    if AssistSession.shared.inProgress {
        AssistSession.shared.requestNewSession(.init(
            server: server,
            pipelineId: pipeline,
            autoStartRecording: autoStartRecording
        ))
        return
    }

    if Current.sceneManager.supportsMultipleScenes, Current.isCatalyst {
        // On macOS, open Assist in a new window/scene
        Current.sceneManager.activateAnyScene(
            for: .assist,
            with: [
                "server": server.identifier.rawValue,
                "pipelineId": pipeline,
                "autoStartRecording": autoStartRecording,
            ]
        )
    } else {
        // On iOS/iPad, present modally as before
        let assistView = UIHostingController(rootView: AssistView.build(
            server: server,
            preferredPipelineId: pipeline,
            autoStartRecording: autoStartRecording
        ))
        assistView.modalPresentationStyle = .fullScreen
        assistView.modalTransitionStyle = .crossDissolve
        webViewController?.presentOverlayController(controller: assistView, animated: true)
    }
}

public func gestureRecognizer(_ gestureRecognizer: UIGestureRecognizer, shouldReceive touch: UITouch) -> Bool {
    // Don't let the wake gesture intercept taps in the secret exit corner
    guard gestureRecognizer === wakeGesture else { return true }

    let settings = KioskModeManager.shared.settings
    guard settings.secretExitGestureEnabled, KioskModeManager.shared.isKioskModeActive else {
        return true
    }

    let location = touch.location(in: view)
    let cornerSize: CGFloat = 80
    let corner = settings.secretExitGestureCorner

    let cornerRect: CGRect
    switch corner {
    case .topLeft:
        cornerRect = CGRect(x: 0, y: 0, width: cornerSize, height: cornerSize)
    case .topRight:
        cornerRect = CGRect(x: view.bounds.width - cornerSize, y: 0, width: cornerSize, height: cornerSize)
    case .bottomLeft:
        cornerRect = CGRect(x: 0, y: view.bounds.height - cornerSize, width: cornerSize, height: cornerSize)
    case .bottomRight:
        cornerRect = CGRect(
            x: view.bounds.width - cornerSize,
            y: view.bounds.height - cornerSize,
            width: cornerSize,
            height: cornerSize
        )
    }

    // If touch is in the corner, don't let wake gesture receive it
    return !cornerRect.contains(location)
}

private func scheduleShowCameraFallbackNotification(userInfo: [AnyHashable: Any]?) {
    guard let entityId = cameraEntityId(from: userInfo) else {
        Current.Log.error("Received show_camera push command without a valid camera entity_id")
        return
    }

    let content = UNMutableNotificationContent()
    content.body = L10n.CameraPlayer.Notification.body
    content.sound = .default
    var fallbackUserInfo: [AnyHashable: Any] = [
        "homeassistant": [
            "command": "show_camera",
            "entity_id": entityId,
        ],
    ]
    if let webhookId = webhookId(from: userInfo) {
        fallbackUserInfo["webhook_id"] = webhookId
    }
    content.userInfo = fallbackUserInfo

    Current.userNotificationCenter.add(UNNotificationRequest(
        identifier: "show_camera.\(entityId)",
        content: content,
        trigger: nil
    )) { error in
        if let error {
            Current.Log.error("Failed to schedule show_camera fallback notification: \(error)")
        }
    }
}

func scene(
    _ scene: UIScene,
    willConnectTo session: UISceneSession,
    options connectionOptions: UIScene.ConnectionOptions
) {
    guard let scene = scene as? UIWindowScene else { return }

    self.scene = scene

    let config = basicConfig(in: scene.traitCollection)

    scene.title = config.title

    with(scene.sizeRestrictions) {
        if scene.traitCollection.userInterfaceIdiom == .mac {
            $0?.minimumSize = CGSize(width: 600.0, height: 200.0)
        } else {
            $0?.maximumSize.width = 800.0
            $0?.minimumSize.width = 300.0
        }
    }

    // never activate these basic scenes scene for anything incoming
    scene.activationConditions.canActivateForTargetContentIdentifierPredicate = NSPredicate(value: false)

    let window = UIWindow(haScene: scene)
    window.rootViewController = config.rootViewController
    self.window = window

    #if targetEnvironment(macCatalyst)
    if let titlebar = scene.titlebar {
        titlebar.titleVisibility = .hidden
        titlebar.toolbar = nil
    }
    #endif

    informManager(from: connectionOptions)
}

public func handle(intent: AddWebFeedIntent) async -> AddWebFeedIntentResponse {
	guard let url = intent.url, let extensionContainers = await ExtensionContainersFile.read() else {
		return AddWebFeedIntentResponse(code: .failure, userActivity: nil)
	}

	let account: ExtensionAccount? = {
		if let accountName = intent.accountName {
			return extensionContainers.findAccount(forName: accountName)
		} else {
			return extensionContainers.accounts.first
		}
	}()

	guard let validAccount = account else {
		return AddWebFeedIntentResponse(code: .failure, userActivity: nil)
	}

	let container: ExtensionContainer? = {
		if let folderName = intent.folderName {
			return validAccount.findFolder(forName: folderName)
		} else {
			return validAccount
		}
	}()

	guard let validContainer = container, let containerID = validContainer.containerID else {
		return AddWebFeedIntentResponse(code: .failure, userActivity: nil)
	}

	let request = ExtensionFeedAddRequest(name: nil, feedURL: url, destinationContainerID: containerID)
	ExtensionFeedAddRequestFile.save(request)
	return AddWebFeedIntentResponse(code: .success, userActivity: nil)
}

public func evaluate(_ trust: SecTrust, forHost host: String) throws {
    guard !keys.isEmpty else {
        throw AFError.serverTrustEvaluationFailed(reason: .noPublicKeysFound)
    }

    if performDefaultValidation {
        try trust.af.performDefaultValidation(forHost: host)
    }

    if validateHost {
        try trust.af.performValidation(forHost: host)
    }

    let pinnedKeysInServerKeys: Bool = {
        for serverPublicKey in trust.af.publicKeys {
            if keys.contains(serverPublicKey) {
                return true
            }
        }
        return false
    }()

    if !pinnedKeysInServerKeys {
        throw AFError.serverTrustEvaluationFailed(reason: .publicKeyPinningFailed(host: host,
                                                                                  trust: trust,
                                                                                  pinnedKeys: keys,
                                                                                  serverKeys: trust.af.publicKeys))
    }
}

