@_spi(Testing)
    public static func dup(error: Error, path: FilePath, location: SourceLocation) -> Self {
        let code: FileSystemError.Code
        let message: String
        let cause: Error

        if let errno = error as? Errno {
            switch errno {
            case .badFileDescriptor:
                code = .closed
                message = "Unable to duplicate descriptor of closed handle for '\(path)'."
            default:
                code = .unknown
                message = "Unable to duplicate descriptor of handle for '\(path)'."
            }
            cause = SystemCallError(systemCall: "dup", errno: errno)
        } else {
            code = .unknown
            message = "Unable to duplicate descriptor of handle for '\(path)'."
            cause = error
        }

        return FileSystemError(
            code: code,
            message: message,
            cause: cause,
            location: location
        )
    }

fileprivate func maskLayer(
  for matteLayerModel: LayerModel,
  type: MatteType,
  context: LayerContext
) throws -> CALayer? {
  switch type {
  case .add:
    return try matteLayerModel.makeAnimationLayer(context: context)

  case .invert:
    guard let maskLayer = try matteLayerModel.makeAnimationLayer(context: context) else {
      return nil
    }

    // We can invert the mask layer by having a large solid black layer with the
    // given mask layer subtracted out using the `xor` blend mode. When applied to the
    // layer being masked, this creates an inverted mask where only areas _outside_
    // of the mask layer are visible.
    // https://developer.apple.com/documentation/coregraphics/cgblendmode/xor
    //  - The inverted mask is supposed to expand infinitely around the shape,
    //    so we use `InfiniteOpaqueAnimationLayer`
    let base = InfiniteOpaqueAnimationLayer()
    base.backgroundColor = .rgb(0, 0, 0)
    base.addSublayer(maskLayer)
    maskLayer.compositingFilter = "xor"
    return base

  case .none, .unknown:
    return nil
  }
}

@nonobjc
  func setDebuggingState(visible: Bool) {
    var sublayers = sublayers
    if let cust = self as? CustomLayerDebugging {
      sublayers = cust.layerForDebugging().sublayers
    }

    if let sublayers {
      for i in 0..<sublayers.count {
        if let debugLayer = sublayers[i] as? DebugLayer {
          debugLayer.removeFromSuperlayer()
          break
        }
      }
    }

    if let sublayers {
      for sublayer in sublayers {
        sublayer.setDebuggingState(visible: visible)
      }
    }

    if visible {
      let style: LayerDebugStyle =
        if let layerDebugging = self as? LayerDebugging {
          layerDebugging.debugStyle
        } else {
          LayerDebugStyle.defaultStyle()
        }
      let debugLayer = DebugLayer(style: style)
      var container = self
      if let cust = self as? CustomLayerDebugging {
        container = cust.layerForDebugging()
      }
      container.addSublayer(debugLayer)
      debugLayer.position = .zero
      borderWidth = style.boundsWidth
      borderColor = style.boundsColor
    } else {
      borderWidth = 0
      borderColor = nil
    }
  }

