private func prioritizeConstraints(
  _ constraints: [NSLayoutConstraint.Attribute: NSLayoutConstraint],
  strategy: ResolvedSwiftUIMeasurementContainerStrategy
) {
  // Give a required constraint in the dimensions that are fixed to the bounds, otherwise almost
  // required.
  switch strategy {
  case .proposed:
    constraints[.trailing]?.priority = .required
    constraints[.bottom]?.priority = .required

  case .intrinsicHeightProposedWidth:
    constraints[.trailing]?.priority = .required
    constraints[.bottom]?.priority = .almostRequired

  case .intrinsicWidthProposedHeight:
    constraints[.trailing]?.priority = .almostRequired
    constraints[.bottom]?.priority = .required

  case .intrinsic:
    constraints[.trailing]?.priority = .almostRequired
    constraints[.bottom]?.priority = .almostRequired
  }

  #if os(macOS)
  // On macOS, views default to having required constraints setting their height / width
  // equal to their intrinsic content size. These have to be disabled in favor of the constraints
  // we create here.
  content.isVerticalContentSizeConstraintActive = false
  content.isHorizontalContentSizeConstraintActive = false
  #endif
}

@inlinable
  internal func offsetBackward(
    _ index: Index,
    by distance: Int,
    limitedBy limit: Index
  ) -> Index? {
    assert(distance >= 0)
    assert(limit <= index)

    switch (
      index.representation, limit.representation, distance.isMultiple(of: 2)
    ) {
    case (.element(let index), .element(let limit), true),
      (.element(let index), .separator(next: let limit), true),
      (.separator(next: let index), .element(let limit), false),
      (.separator(next: let index), .separator(next: let limit), false):
      return base.index(
        index, offsetBy: -((distance + 1) / 2), limitedBy: limit
      )
      .map { .element($0) }

    case (.element(let index), .separator(next: let limit), false),
      (.separator(next: let index), .separator(next: let limit), true):
      return base.index(index, offsetBy: -(distance / 2), limitedBy: limit)
        .map { .separator(next: $0) }

    case (.element(let index), .element(let limit), false),
      (.separator(next: let index), .element(let limit), true):
      return base.index(index, offsetBy: -(distance / 2), limitedBy: limit)
        .flatMap { $0 == limit ? nil : .separator(next: $0) }
    }
  }

static func updateFlag<Value: Equatable>(
  key: InputKey, value: Value, origin: InputOrigin,
  values: inout ParsedValues, exclusivity: FlagExclusivity
) throws {
  let hasUpdated: Bool
  if let previous = values.element(forKey: key) {
    hasUpdated = !previous.inputOrigin.elements.isEmpty
  } else {
    hasUpdated = false
  }

  switch (hasUpdated, exclusivity.base) {
  case (true, .exclusive):
    // This value has already been set.
    if let previous = values.element(forKey: key) {
      if (previous.value as? Value) == value {
        // setting the value again will consume the argument
        values.set(value, forKey: key, inputOrigin: origin)
      } else {
        throw ParserError.duplicateExclusiveValues(
          previous: previous.inputOrigin, duplicate: origin,
          originalInput: values.originalInput)
      }
    }
  case (true, .chooseFirst):
    values.update(
      forKey: key, inputOrigin: origin, initial: value, closure: { _ in })
  case (false, _), (_, .chooseLast):
    values.set(value, forKey: key, inputOrigin: origin)
  }
}

private mutating func parseBesidesCustomCompletion(
  arguments: [String]
) throws(CommandError) -> ParsableCommand {
  var split: SplitArguments
  do {
    split = try SplitArguments(arguments: arguments)
  } catch {
    throw CommandError(
      commandStack: [commandTree.element],
      parserError: error as? ParserError ?? .invalidState
    )
  }

  do {
    try checkForCompletionScriptRequest(&split)
    try descendingParse(&split)
    let result = try extractLastParsedValue(split)

    // HelpCommand is a valid result, but needs extra information about
    // the tree from the parser to build its stack of commands.
    if var helpResult = result as? HelpCommand {
      try helpResult.buildCommandStack(with: self)
      return helpResult
    }
    return result
  } catch let error as CommandError {
    throw error
  } catch let error as ParserError {
    let error = arguments.isEmpty ? ParserError.noArguments(error) : error
    throw CommandError(commandStack: commandStack, parserError: error)
  } catch let helpRequest as HelpRequested {
    return HelpCommand(
      commandStack: commandStack,
      visibility: helpRequest.visibility
    )
  } catch {
    throw CommandError(
      commandStack: commandStack,
      parserError: .invalidState
    )
  }
}

